enum AppLink: Identifiable, Hashable {
    case passwordReset(token: String)
    case other(path: String) // For other potential deep links
    case home // Default state

    var id: String {
        switch self {
        case .passwordReset(let token):
            return "passwordReset-\(token)"
        case .other(let path):
            return "other-\(path)"
        case .home:
            return "home"
        }
    }
}

struct ContentView: View {
    @State private var activeLink: AppLink? = .home

    var body: some View {
        NavigationStack {
            VStack {
                if activeLink == .home {
                    Text("Welcome to My App!")
                        .font(.largeTitle)
                        .padding()
                    Text("This is the main screen.")
                        .padding()
                } else {
                    // This block will be replaced by the navigation destination
                    EmptyView()
                }
            }
            .navigationDestination(for: AppLink.self) { link in
                switch link {
                case .passwordReset(let token):
                    PasswordResetView(token: token)
                case .other(let path):
                    Text("Unhandled Deep Link: \(path)")
                        .font(.title)
                case .home:
                    // Should not happen if we navigate to .home directly, but good for completeness
                    Text("Welcome to My App!")
                        .font(.largeTitle)
                        .padding()
                    Text("This is the main screen.")
                        .padding()
                }
            }
        }
        .onOpenURL { url in
            handleUniversalLink(url)
        }
    }

    private func handleUniversalLink(_ url: URL) {
        print("Received universal link: \(url)")
        guard url.scheme == "https" else {
            print("Not an HTTPS URL.")
            return
        }

        guard url.host == "myapp.com" else {
            print("Host does not match 'myapp.com'.")
            return
        }

        if url.pathComponents.contains("reset-password") {
            if let components = URLComponents(url: url, resolvingAgainstBaseURL: false),
               let queryItems = components.queryItems {
                for item in queryItems {
                    if item.name == "token", let token = item.value {
                        print("Found password reset token: \(token)")
                        activeLink = .passwordReset(token: token)
                        return
                    }
                }
            }
            print("Password reset link without a token.")
            activeLink = .other(path: url.path) // Or show an error
        } else {
            print("Unhandled path: \(url.path)")
            activeLink = .other(path: url.path)
        }
    }
}

